Hello ! 

I am trying to make a search on multiple columns. I use this directive:
```
app.directive('customSearch',function(){
	return {
		restrict:'A',
		require:'^stTable',
		scope:true,
		link:function(scope, element, attr, ctrl){
			var tableState=ctrl.tableState();
			scope.$watch('filterValue',function(value){
				tableState.search = {};
				if(value){
					ctrl.search(value, 'title');
					ctrl.search(value, 'counter');
				} else {
					ctrl.search();
				}
			})
		}
	};
});
```
The problem is that the ctrl.search are cumulative. Is there a way to get smart-table to search on title OR counter ? 

Thanks !

